// ── Exports & Helpers ────────────────────────────────────────────

export { OPERATIONS as OPERATION_REGISTRY };
export { TAGS, TAG_GROUPS };
/** @deprecated Use TAGS */
export const CATEGORIES = TAGS;

export function getAllTagGroups(): Array<TagGroupInfo & { tagInfos: Array<TagInfo & { operations: OperationInfo[] }> }> {
  const opsByTag = new Map<string, OperationInfo[]>();
  for (const op of Object.values(OPERATIONS)) {
    const key = op.tag || op.category;
    if (!opsByTag.has(key)) opsByTag.set(key, []);
    opsByTag.get(key)!.push(op);
  }
  return Object.values(TAG_GROUPS).map(group => ({
    ...group,
    tagInfos: group.tags.map(tagSlug => ({
      ...(TAGS[tagSlug] || { name: tagSlug, displayName: tagSlug, tagGroup: group.name }),
      operations: opsByTag.get(tagSlug) || [],
    })),
  }));
}

export function getAllCategories(): Array<TagInfo & { operations: OperationInfo[] }> {
  const catOps = new Map<string, OperationInfo[]>();
  for (const op of Object.values(OPERATIONS)) {
    const key = op.tag || op.category;
    if (!catOps.has(key)) catOps.set(key, []);
    catOps.get(key)!.push(op);
  }
  return Object.values(TAGS).map(tag => ({
    ...tag,
    operations: catOps.get(tag.name) || [],
  }));
}

export function getCategory(name: string): (TagInfo & { operations: OperationInfo[] }) | undefined {
  const needle = name.toLowerCase();
  const tag = Object.values(TAGS).find(t => t.name === needle || t.displayName.toLowerCase() === needle);
  if (!tag) return undefined;
  const ops = Object.values(OPERATIONS).filter(o => (o.tag || o.category) === tag.name);
  return { ...tag, operations: ops };
}

export function getTagGroup(name: string): (TagGroupInfo & { tagInfos: Array<TagInfo & { operations: OperationInfo[] }> }) | undefined {
  const needle = name.toLowerCase();
  const group = Object.values(TAG_GROUPS).find(g => g.name === needle || g.displayName.toLowerCase() === needle);
  if (!group) return undefined;
  const opsByTag = new Map<string, OperationInfo[]>();
  for (const op of Object.values(OPERATIONS)) {
    const key = op.tag || op.category;
    if (group.tags.includes(key)) {
      if (!opsByTag.has(key)) opsByTag.set(key, []);
      opsByTag.get(key)!.push(op);
    }
  }
  return {
    ...group,
    tagInfos: group.tags.map(tagSlug => ({
      ...(TAGS[tagSlug] || { name: tagSlug, displayName: tagSlug, tagGroup: group.name }),
      operations: opsByTag.get(tagSlug) || [],
    })),
  };
}

export function findOperation(nameOrId: string): OperationInfo | undefined {
  const needle = nameOrId.toLowerCase();

  if (needle.includes(".")) {
    const [catName, methodName] = needle.split(".", 2);
    return Object.values(OPERATIONS).find(
      o => ((o.tag || o.category).toLowerCase() === catName || o.tagGroup.toLowerCase() === catName)
        && (o.methodName.toLowerCase() === methodName || o.operationId.toLowerCase() === methodName),
    );
  }

  const matches = Object.values(OPERATIONS).filter(
    o => o.methodName.toLowerCase() === needle || o.operationId.toLowerCase() === needle,
  );

  if (matches.length === 1) return matches[0];

  if (matches.length > 1) {
    const options = matches.map(m => `  • ${m.tag || m.category}.${m.methodName}`).join("\n");
    throw new Error(
      `Ambiguous operation "${nameOrId}" found in ${matches.length} tags:\n${options}\n\n`
      + "Use the qualified form: <tag>.<operation>",
    );
  }

  return undefined;
}

export function searchOperations(query: string): OperationInfo[] {
  const needle = query.toLowerCase();
  return Object.values(OPERATIONS).filter(op =>
    op.methodName.toLowerCase().includes(needle)
    || op.operationId.toLowerCase().includes(needle)
    || op.summary?.toLowerCase().includes(needle)
    || (op.tag || op.category).includes(needle)
    || op.tagGroup.includes(needle),
  );
}

export function getTotalOperationCount(): number {
  return Object.keys(OPERATIONS).length;
}
